function NextJSIcon() {
  return (
    <svg role="img" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
      <title>Next.js</title>
      <path
        fill="currentColor"
        d="M18.665 21.978C16.758 23.255 14.465 24 12 24 5.377 24 0 18.623 0 12S5.377 0 12 0s12 5.377 12 12c0 3.583-1.574 6.801-4.067 9.001L9.219 7.2H7.2v9.596h1.615V9.251l9.85 12.727Zm-3.332-8.533 1.6 2.061V7.2h-1.6v6.245Z"
      />
    </svg>
  );
}

function TechBadge({ slug }: { slug: string }) {
  const abbr = slug.replace(/-/g, "").slice(0, 2).toUpperCase();
  return (
    <span className="flex size-5 items-center justify-center rounded border border-current text-[7px] leading-none font-bold">
      {abbr}
    </span>
  );
}

const techMap: Record<string, TechEntry> = {
  tailwindcss: { label: "Tailwind CSS", icon: <TailwindCSSIcon /> },
  "react-router": { label: "React Router", icon: <ReactRouterIcon /> },
  "apollo-client": { label: "Apollo Client", icon: <ApolloClientIcon /> },
  "react-bootstrap": { label: "React Bootstrap", icon: <ReactBootstrapIcon /> },
  redux: { label: "Redux", icon: <ReduxIcon /> },
  react: { label: "React", icon: <ReactIcon /> },
  typescript: { label: "TypeScript", icon: <TypeScriptIcon /> },
  nextjs: { label: "Next.js", icon: <NextJSIcon /> },
  "next-js": { label: "Next.js", icon: <NextJSIcon /> },
};

type TechIconProps = { tech: string };

export function TechIcon({ tech }: TechIconProps) {
  const slug = tech.trim().toLowerCase();
  const entry = techMap[slug];
  const label = entry?.label ?? slug.replace(/-/g, " ");
  const icon = entry?.icon ?? <TechBadge slug={slug} />;

  return (
    <Provider delayDuration={100}>
      <Root>
        <Trigger asChild>
          <li className="size-5 cursor-default text-(--icon-primary) focus:outline-none">
            {icon}
          </li>
        </Trigger>
        <Content className="TooltipContent" sideOffset={5}>
          <Text
            className="text-neutral-50 capitalize dark:text-neutral-950"
            variant="label"
          >
            {label}
          </Text>
          <Arrow className="TooltipArrow" />
        </Content>
      </Root>
    </Provider>
  );
}
